package com.example.paymentprocessing

import android.content.Context
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKeys
import com.android.billingclient.api.*
import java.math.BigDecimal

class PaymentProcessor(context: Context) {

    private val billingClient = BillingClient.newBuilder(context)
        .setListener { purchaseResult -> handlePurchase(purchaseResult) }
        .enablePendingPurchases()
        .build()

    private val sharedPreferences = EncryptedSharedPreferences.create(
        "payment_prefs",
        MasterKeys.getOrCreate(MasterKeys.AES256_GCM_SPEC),
        context,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    init {
        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {}

            override fun onBillingServiceDisconnected() {}
        })
    }

    fun initiatePurchase(productId: String, price: BigDecimal) {
        val skuDetailsParams = SkuDetailsParams.newBuilder()
            .setSkusList(listOf(productId))
            .setType(BillingClient.SkuType.INAPP)
            .build()

        billingClient.querySkuDetailsAsync(skuDetailsParams) { billingResult, skuDetailsList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !skuDetailsList.isNullOrEmpty()) {
                val flowParams = BillingFlowParams.newBuilder()
                    .setSkuDetails(skuDetailsList[0])
                    .build()

                billingClient.launchBillingFlow((context as MainActivity), flowParams)
            }
        }
    }

    private fun handlePurchase(purchaseResult: Purchase) {
        // Handle the purchase, e.g., verify signature, update user balance
        if (purchaseResult.purchaseState == Purchase.PurchaseState.PURCHASED && !purchaseResult.isAcknowledged) {
            val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                .setPurchaseToken(purchaseResult.purchaseToken)
                .build()

            billingClient.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    // Update user balance or perform other actions
                }
            }
        }
    }

    fun saveWalletTransaction(transactionId: String, amount: BigDecimal) {
        sharedPreferences.edit().putString(transactionId, amount.toPlainString()).apply()
    }

    fun getWalletTransactions(): Map<String, BigDecimal> {
        return sharedPreferences.all.mapValues { (_, value) -> BigDecimal(value as String) }
    }
}